from fastapi import FastAPI, Response
from contextlib import asynccontextmanager
from datetime import datetime, timezone
import asyncio
import logging

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

app = FastAPI()

# Track startup state
app_ready = False


# --- Dependency health checkers ---
async def check_database() -> dict:
    """Check database connectivity."""
    try:
        # Replace with real DB check: await db.execute("SELECT 1")
        await asyncio.sleep(0.01)  # Simulated
        return {"database": {"status": "up", "latency_ms": 10}}
    except Exception as e:
        return {"database": {"status": "down", "error": str(e)}}

async def check_redis() -> dict:
    """Check Redis connectivity."""
    try:
        # Replace with real check: await redis.ping()
        await asyncio.sleep(0.01)  # Simulated
        return {"redis": {"status": "up", "latency_ms": 5}}
    except Exception as e:
        return {"redis": {"status": "down", "error": str(e)}}

async def check_external_api() -> dict:
    """Check external API availability."""
    try:
        await asyncio.sleep(0.01)
        return {"external_api": {"status": "up"}}
    except Exception as e:
        return {"external_api": {"status": "down", "error": str(e)}}


# --- Liveness: Is the process alive? ---
@app.get("/health/live")
async def liveness():
    """Lightweight check. No external dependencies.
    If this fails, the container should be restarted."""
    return {
        "status": "alive",
        "timestamp": datetime.now(timezone.utc).isoformat(),
    }


# --- Readiness: Can we serve traffic? ---
@app.get("/health/ready")
async def readiness(response: Response):
    """Checks all critical dependencies.
    If this fails, traffic should be routed elsewhere."""
    checks = await asyncio.gather(
        check_database(),
        check_redis(),
    )

    dependencies = {}
    for check in checks:
        dependencies.update(check)

    all_healthy = all(
        dep["status"] == "up"
        for dep in dependencies.values()
    )

    if not all_healthy:
        response.status_code = 503

    return {
        "status": "ready" if all_healthy else "not_ready",
        "dependencies": dependencies,
        "timestamp": datetime.now(timezone.utc).isoformat(),
    }


# --- Startup: Has initialization completed? ---
@app.get("/health/startup")
async def startup_check(response: Response):
    """Returns 503 until the app has fully started."""
    if not app_ready:
        response.status_code = 503
        return {"status": "starting"}
    return {"status": "started"}


# --- Combined health endpoint ---
@app.get("/health")
async def combined_health(response: Response):
    """Single endpoint with all health information."""
    checks = await asyncio.gather(
        check_database(),
        check_redis(),
        check_external_api(),
    )
    dependencies = {}
    for check in checks:
        dependencies.update(check)

    all_healthy = all(
        dep["status"] == "up" for dep in dependencies.values()
    )

    if not all_healthy:
        response.status_code = 503

    return {
        "status": "healthy" if all_healthy else "degraded",
        "version": "1.2.3",
        "dependencies": dependencies,
    }


# --- Lifespan: mark app as ready after init ---
@asynccontextmanager
async def lifespan(app: FastAPI):
    global app_ready
    # Initialization (load models, warm caches, etc.)
    logger.info("Initializing...")
    await asyncio.sleep(0.1)  # Simulate slow startup
    app_ready = True
    logger.info("App is ready")
    yield
    app_ready = False

